var myCar = new Car("Toyota", "Camry", 2022);
myCar.DisplayInfo();

public class Car
{
    // Properties
    public string Make { get; set; }
    public string Model { get; set; }
    public int Year { get; private set; }

    // Constructor
    public Car(string make, string model, int year)
    {
        Make = make;
        Model = model;
        Year = year;
    }

    // Method
    public void DisplayInfo()
    {
        Console.WriteLine($"Car Info: {Year} {Make} {Model}");
    }
}

var fruits = new List<string> { "Apple", "Banana", "Cherry", "Apricot", "Blueberry" };

// 1. Filter fruits that start with 'A'
var a_fruits = fruits.Where(f => f.StartsWith("A"));
Console.WriteLine("Fruits starting with 'A': " + string.Join(", ", a_fruits));

// 2. Project to a list of fruit lengths
var fruitLengths = fruits.Select(f => f.Length);
Console.WriteLine("\nFruit name lengths: " + string.Join(", ", fruitLengths));

// 3. Filter and order by name
var longFruitsSorted = fruits
    .Where(f => f.Length > 5)
    .OrderBy(f => f);

Console.WriteLine("\nLong fruits, sorted: " + string.Join(", ", longFruitsSorted));

string filePath = "example.txt";
string content = "Hello from C#!\nThis is the second line.";

// Write to a file, overwriting it if it exists.
File.WriteAllText(filePath, content);
Console.WriteLine($"Successfully wrote to {filePath}");

// Read all text from a file.
if (File.Exists(filePath))
{
    string readContent = File.ReadAllText(filePath);
    Console.WriteLine($"\n--- Contents of {filePath} ---");
    Console.WriteLine(readContent);
}
else
{
    Console.WriteLine($"File not found: {filePath}");
}

using var client = new HttpClient();

// The Main method can be async in modern C#
await FetchDataAsync();

async Task FetchDataAsync()
{
    string url = "https://jsonplaceholder.typicode.com/todos/1";
    Console.WriteLine($"Fetching data from {url}...");

    try
    {
        HttpResponseMessage response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode(); // Throws if status is not 2xx

        string responseBody = await response.Content.ReadAsStringAsync();
        Console.WriteLine("\n--- Response ---");
        Console.WriteLine(responseBody);
    }
    catch (HttpRequestException e)
    {
        Console.WriteLine($"\nError: {e.Message}");
    }
}

