// 1. Define the interface (the contract)
public interface IMessageService
{
    void SendMessage(string message);
}

// 2. Implement the interface
public class EmailService : IMessageService
{
    public void SendMessage(string message)
    {
        Console.WriteLine($"Sending email: {message}");
    }
}

// 3. Use the interface (Dependency Injection via constructor)
public class NotificationManager
{
    private readonly IMessageService _messageService;

    public NotificationManager(IMessageService messageService)
    {
        _messageService = messageService;
    }

    public void Notify(string notification)
    {
        _messageService.SendMessage(notification);
    }
}

// --- Usage ---
var emailService = new EmailService();
var notificationManager = new NotificationManager(emailService);
notificationManager.Notify("Your order has shipped!");

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// Define a record for our data structure
public record Product(int Id, string Name, decimal Price);

// Create a sample list of products
var products = new List<Product>
{
    new Product(1, "Laptop", 1200.00m),
    new Product(2, "Mouse", 25.50m),
    new Product(3, "Keyboard", 75.00m)
};

// Define a GET endpoint for the root URL
app.MapGet("/", () => "Hello, Minimal API!");

// Define a GET endpoint to return all products as JSON
app.MapGet("/products", () => products);

// Define a GET endpoint for a single product by ID
app.MapGet("/products/{id}", (int id) =>
{
    var product = products.FirstOrDefault(p => p.Id == id);
    return product is not null ? Results.Ok(product) : Results.NotFound();
});

app.Run();
